from dataclasses import dataclass
from typing import List, Tuple

import torch
import torch.nn as nn
import torch.nn.functional as F


class LayerNorm2d(nn.Module):
    def __init__(self, dim: int, eps: float = 1e-6):
        super().__init__()
        self.weight = nn.Parameter(torch.ones(dim))
        self.bias = nn.Parameter(torch.zeros(dim))
        self.eps = eps

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        mean = x.mean(dim=1, keepdim=True)
        var = (x - mean).pow(2).mean(dim=1, keepdim=True)
        x = (x - mean) / torch.sqrt(var + self.eps)
        return x * self.weight[:, None, None] + self.bias[:, None, None]


class SphericalPositionalEncoding(nn.Module):
    def __init__(self, out_dim: int):
        super().__init__()
        hidden = max(32, out_dim // 2)
        self.net = nn.Sequential(
            nn.Conv2d(3, hidden, kernel_size=1),
            nn.GELU(),
            nn.Conv2d(hidden, out_dim, kernel_size=1),
        )

    @staticmethod
    def build_xyz(height: int, width: int, device: torch.device, dtype: torch.dtype) -> torch.Tensor:
        v = torch.linspace(0.5 / height, 1.0 - 0.5 / height, height, device=device, dtype=dtype)
        u = torch.linspace(0.5 / width, 1.0 - 0.5 / width, width, device=device, dtype=dtype)
        vv, uu = torch.meshgrid(v, u, indexing='ij')
        lon = (uu * 2.0 - 1.0) * math.pi
        lat = (0.5 - vv) * math.pi
        x = torch.cos(lat) * torch.cos(lon)
        y = torch.sin(lat)
        z = torch.cos(lat) * torch.sin(lon)
        return torch.stack([x, y, z], dim=0).unsqueeze(0)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        _, _, h, w = x.shape
        xyz = self.build_xyz(h, w, x.device, x.dtype).expand(x.shape[0], -1, -1, -1)
        return self.net(xyz)


class DepthwiseSeparableConv(nn.Module):
    def __init__(self, dim: int):
        super().__init__()
        self.dw = nn.Conv2d(dim, dim, kernel_size=3, padding=1, groups=dim)
        self.pw = nn.Conv2d(dim, dim, kernel_size=1)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return self.pw(self.dw(x))


class SphericalAttentionBlock(nn.Module):
    def __init__(self, dim: int, heads: int = 4, mlp_ratio: float = 2.0, dropout: float = 0.0):
        super().__init__()
        self.norm1 = LayerNorm2d(dim)
        self.qkv = nn.Conv2d(dim, dim * 3, kernel_size=1)
        self.local_mix = DepthwiseSeparableConv(dim)
        self.proj = nn.Conv2d(dim, dim, kernel_size=1)
        self.norm2 = LayerNorm2d(dim)
