        x1 = self.norm1(x)
        qkv = self.qkv(x1)
        q, k, v = torch.chunk(qkv, 3, dim=1)
        q = q.reshape(b, self.heads, c // self.heads, h * w).transpose(-1, -2)
        k = k.reshape(b, self.heads, c // self.heads, h * w)
        v = v.reshape(b, self.heads, c // self.heads, h * w).transpose(-1, -2)
        attn = torch.matmul(q, k) * self.scale
        attn = torch.softmax(attn, dim=-1)
        x_attn = torch.matmul(attn, v)
        x_attn = x_attn.transpose(-1, -2).reshape(b, c, h, w)
        x_attn = self.proj(x_attn + self.local_mix(x1))
