    def __init__(self, dim: int, depth: int, heads: int):
        super().__init__()
        self.blocks = nn.Sequential(*[SphericalAttentionBlock(dim, heads=heads) for _ in range(depth)])

    def forward(self, x: torch.Tensor) -> torch.Tensor:
