    def __init__(self, cfg: SphereUFormerConfig = SphereUFormerConfig()):
        super().__init__()
        self.cfg = cfg
        dims = [cfg.base_dim * (2 ** i) for i in range(len(cfg.depths))]
        self.stem = nn.Conv2d(cfg.in_channels, dims[0], kernel_size=3, padding=1)
        self.pos0 = SphericalPositionalEncoding(dims[0])

        self.encoders = nn.ModuleList()
        self.downs = nn.ModuleList()
        for i, (dim, depth, heads) in enumerate(zip(dims, cfg.depths, cfg.heads)):
            self.encoders.append(EncoderStage(dim, depth, heads))
            if i < len(dims) - 1:
                self.downs.append(Downsample(dim, dims[i + 1]))

        self.ups = nn.ModuleList()
        self.decoders = nn.ModuleList()
        for i in range(len(dims) - 1, 0, -1):
            self.ups.append(Upsample(dims[i], dims[i - 1]))
            self.decoders.append(DecoderStage(dims[i - 1], cfg.depths[i - 1], cfg.heads[i - 1]))

        self.fuse = nn.Conv2d(dims[0], dims[0], kernel_size=3, padding=1)
        self.rgb_head = nn.Sequential(
            nn.Conv2d(dims[0], dims[0], kernel_size=3, padding=1),
            nn.GELU(),
            nn.Conv2d(dims[0], cfg.out_rgb_channels, kernel_size=1),
            nn.Sigmoid(),
        )
        self.depth_head = nn.Sequential(
            nn.Conv2d(dims[0], dims[0], kernel_size=3, padding=1),
            nn.GELU(),
            nn.Conv2d(dims[0], cfg.out_depth_channels, kernel_size=1),
            nn.ReLU(),
        )

    def forward(self, x: torch.Tensor) -> dict:
        x = self.stem(x)
        x = x + self.pos0(x)
        skips: List[torch.Tensor] = []
        for i, enc in enumerate(self.encoders):
            x = enc(x)
            skips.append(x)
            if i < len(self.downs):
                x = self.downs[i](x)

        for up, dec, skip in zip(self.ups, self.decoders, reversed(skips[:-1])):
            x = up(x)
            if x.shape[-2:] != skip.shape[-2:]:
                x = F.interpolate(x, size=skip.shape[-2:], mode='bilinear', align_corners=False)
            x = x + skip
            x = dec(x)

        x = self.fuse(x)
        rgb = self.rgb_head(x)
        depth = self.depth_head(x)
        return {'rgb': rgb, 'depth': depth}


def build_model(**kwargs) -> SphereUFormer:
    cfg = SphereUFormerConfig(**kwargs)
    return SphereUFormer(cfg)
